import React from "react";
import { BrowserRouter as Route, Switch } from "react-router-dom";
import { Landing } from "UserPages/Landing";
import { About } from "UserPages/About";
import { Contact } from "UserPages/Contact";
import { Solutions } from "UserPages/Solutions";

export const Pages = [
  { page: Landing, path: "HOME", name: "Home" },
  { page: About, path: "/ABOUT", name: "About" },
  { page: Solutions, path: "/SOLUTIONS", name: "Solutions" },
  { page: Landing, path: "/", name: "Home" },
  { page: Contact, path: "CONTACT", name: "Contact" },
];

export const ScreenLayoutInner = () => {
  return (
    <div>
      <Switch>
        <Route path={Pages[0].path}>
          <>{Pages[0].page}</>
        </Route>
        <Route path={Pages[1].path}>
          <About />
        </Route>
        <Route path={Pages[2].path}>
          <Solutions />
        </Route>
        <Route path={Pages[3].path}>
          <Landing />
        </Route>
        <Route path={Pages[4].path}>
          <Contact />
        </Route>
      </Switch>
    </div>
  );
};
